Here's the standard approach:

**1. Define each theme as a `ResourceDictionary`**

```xml
<!-- Themes/LightTheme.xaml -->
<ResourceDictionary xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
                    xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml">
    <Color x:Key="PageBackground">#FFFFFF</Color>
    <Color x:Key="TextPrimary">#1A1A1A</Color>
    <Color x:Key="AccentColor">#0078D4</Color>
    <!-- ... -->
</ResourceDictionary>
```

Create matching `DarkTheme.xaml` and `HighContrastTheme.xaml` with the same keys but different values.

**2. Build a theme service to swap dictionaries at runtime**

```csharp
public enum AppTheme { Light, Dark, HighContrast }

public static class ThemeService
{
    private static readonly Dictionary<AppTheme, string> ThemeSources = new()
    {
        { AppTheme.Light,        "Themes/LightTheme.xaml" },
        { AppTheme.Dark,         "Themes/DarkTheme.xaml" },
        { AppTheme.HighContrast, "Themes/HighContrastTheme.xaml" },
    };

    public static void ApplyTheme(AppTheme theme)
    {
        var mergedDicts = Application.Current!.Resources.MergedDictionaries;

        // Remove the current theme dictionary (always the last one added)
        var existing = mergedDicts
            .FirstOrDefault(d => d.Source?.OriginalString.StartsWith("Themes/") == true);
        if (existing is not null)
            mergedDicts.Remove(existing);

        // Add the new one
        mergedDicts.Add(new ResourceDictionary
        {
            Source = new Uri(ThemeSources[theme], UriKind.Relative)
        });

        // Persist the choice
        Preferences.Set("app_theme", theme.ToString());
    }

    public static AppTheme GetSavedTheme()
    {
        var saved = Preferences.Get("app_theme", AppTheme.Light.ToString());
        return Enum.TryParse<AppTheme>(saved, out var t) ? t : AppTheme.Light;
    }
}
```

**3. Apply the saved theme on startup (`App.xaml.cs`)**

```csharp
public App()
{
    InitializeComponent();
    ThemeService.ApplyTheme(ThemeService.GetSavedTheme());
}
```

**4. Add a picker on your settings page**

```xml
<Picker Title="Theme"
        SelectedIndexChanged="OnThemeChanged">
    <Picker.Items>
        <x:String>Light</x:String>
        <x:String>Dark</x:String>
        <x:String>High Contrast</x:String>
    </Picker.Items>
</Picker>
```

```csharp
void OnThemeChanged(object sender, EventArgs e)
{
    var theme = ((Picker)sender).SelectedIndex switch
    {
        1 => AppTheme.Dark,
        2 => AppTheme.HighContrast,
        _ => AppTheme.Light,
    };
    ThemeService.ApplyTheme(theme);
}
```

**5. Reference theme keys with `DynamicResource` (not `StaticResource`)**

```xml
<ContentPage BackgroundColor="{DynamicResource PageBackground}">
    <Label TextColor="{DynamicResource TextPrimary}" Text="Hello!" />
</ContentPage>
```

`DynamicResource` is the key detail — it re-evaluates when the dictionary changes, giving you instant theme switching without reloading pages.
